changeSet.sql:
CREATE TYPE OrganizationEmailTemplateType as ENUM ('VENDOR_EMPLOYEE_INVITATION');

CREATE TABLE organization_email_templates
(
	id serial,
	organization_id integer NOT NULL,
	type OrganizationEmailTemplateType NOT NULL,
	subject text DEFAULT '',
	content text DEFAULT '',

	CONSTRAINT pk_organization_email_templates PRIMARY KEY (id)
);
CREATE INDEX i_organization_email_templates_organization ON organization_email_templates (organization_id);
